import { Notification } from './notification.model';

export interface INotificationRepository {
  create(notification: Omit<Notification, 'id' | 'createdAt'>): Promise<Notification>;
  update(notificationId: string, updates: Partial<Notification>): Promise<Notification>;
  findByRecipient(recipientId: string, options?: { isRead?: boolean; limit?: number }): Promise<Notification[]>;
  findById(notificationId: string): Promise<Notification | null>;
}

export class NotificationRepository implements INotificationRepository {
  constructor(private readonly db: any) {}

  async create(notification: Omit<Notification, 'id' | 'createdAt'>): Promise<Notification> {
    const result = await this.db.query(
      `INSERT INTO notifications (recipient_id, sender_id, type, title, message, metadata, is_read, read_at, created_at)
       VALUES ($1, $2, $3, $4, $5, $6, $7, $8, $9)
       RETURNING *`,
      [
        notification.recipientId,
        notification.senderId,
        notification.type,
        notification.title,
        notification.message,
        notification.metadata,
        notification.isRead,
        notification.readAt,
        new Date()
      ]
    );
    return this.mapToNotification(result.rows[0]);
  }

  async update(notificationId: string, updates: Partial<Notification>): Promise<Notification> {
    const setClauses: string[] = [];
    const values: any[] = [];
    let paramCount = 1;

    if (updates.isRead !== undefined) {
      setClauses.push(`is_read = $${paramCount}`);
      values.push(updates.isRead);
      paramCount++;
    }
    if (updates.readAt !== undefined) {
      setClauses.push(`read_at = $${paramCount}`);
      values.push(updates.readAt);
      paramCount++;
    }

    if (setClauses.length === 0) {
      const existing = await this.findById(notificationId);
      if (!existing) throw new Error(`Notification ${notificationId} not found`);
      return existing;
    }

    values.push(notificationId);
    const result = await this.db.query(
      `UPDATE notifications SET ${setClauses.join(', ')} WHERE id = $${paramCount} RETURNING *`,
      values
    );
    return this.mapToNotification(result.rows[0]);
  }

  async findByRecipient(recipientId: string, options?: { isRead?: boolean; limit?: number }): Promise<Notification[]> {
    let query = 'SELECT * FROM notifications WHERE recipient_id = $1';
    const params: any[] = [recipientId];
    let paramCount = 2;

    if (options?.isRead !== undefined) {
      query += ` AND is_read = $${paramCount}`;
      params.push(options.isRead);
      paramCount++;
    }

    query += ' ORDER BY created_at DESC';

    if (options?.limit) {
      query += ` LIMIT $${paramCount}`;
      params.push(options.limit);
    }

    const result = await this.db.query(query, params);
    return result.rows.map(this.mapToNotification);
  }

  async findById(notificationId: string): Promise<Notification | null> {
    const result = await this.db.query('SELECT * FROM notifications WHERE id = $1', [notificationId]);
    if (result.rows.length === 0) return null;
    return this.mapToNotification(result.rows[0]);
  }

  private mapToNotification(row: any): Notification {
    return {
      id: row.id,
      recipientId: row.recipient_id,
      senderId: row.sender_id,
      type: row.type,
      title: row.title,
      message: row.message,
      metadata: row.metadata,
      isRead: row.is_read,
      readAt: row.read_at,
      createdAt: row.created_at
    };
  }
